import { Accessor, onCleanup, onMount } from "gnim"

export function useEffect(fn: (track: <T>(signal: Accessor<T>) => T) => void) {
    let prevDeps = new Map<Accessor, () => void>()

    const effect = () => {
        const deps = new Set<Accessor>()
        fn((v) => {
            deps.add(v)
            return v.get()
        })

        const newDeps = new Map<Accessor, () => void>()

        for (const [dep, unsub] of prevDeps) {
            if (!deps.has(dep)) {
                unsub()
            } else {
                newDeps.set(dep, unsub)
            }
        }

        for (const dep of deps) {
            if (!newDeps.has(dep)) {
                newDeps.set(dep, dep.subscribe(effect))
            }
        }

        prevDeps = newDeps
    }

    onCleanup(() => {
        for (const [, unsub] of prevDeps) {
            unsub()
        }
    })

    onMount(effect)
}
